# Scoring constants
LINE_CLEAR_SCORES = {1: 100, 2: 300, 3: 500, 4: 800}
GEM_CLEAR_SCORE = 50

class Gem:
    def __init__(self, color):
        self.color = color
        self.marked_for_clear = False

    def __repr__(self):
        return f"Gem({self.color[0].upper()})"

class GameGrid:
    def __init__(self, width=10, height=20):
        self.width = width
        self.height = height
        self.cells = [[None for _ in range(width)] for _ in range(height)]

    def in_bounds(self, x, y):
        return 0 <= x < self.width and 0 <= y < self.height

    def set_cell(self, x, y, value):
        if not self.in_bounds(x, y):
            raise IndexError(f"Position out of bounds: ({x},{y})")
        self.cells[y][x] = value

    def get_cell(self, x, y):
        if not self.in_bounds(x, y):
            raise IndexError(f"Position out of bounds: ({x},{y})")
        return self.cells[y][x]

    def __repr__(self):
        rows = []
        for row in self.cells:
            rows.append(' '.join(str(cell) if cell else '.' for cell in row))
        return '\n'.join(rows)

    def clear_completed_lines(self):
        full_rows = [y for y in range(self.height)
                     if all(self.cells[y][x] is not None for x in range(self.width))]
        for y in full_rows:
            for yy in range(y, 0, -1):
                self.cells[yy] = list(self.cells[yy-1])
            self.cells[0] = [None] * self.width
        return len(full_rows)

    def find_match3(self):
        to_clear = set()
        # Horizontal runs
        for y in range(self.height):
            x = 0
            while x < self.width:
                cell = self.cells[y][x]
                if cell:
                    color = cell.color
                    run = [(x, y)]
                    x2 = x + 1
                    while x2 < self.width and self.cells[y][x2] and self.cells[y][x2].color == color:
                        run.append((x2, y))
                        x2 += 1
                    if len(run) >= 3:
                        to_clear.update(run)
                    x = x2
                else:
                    x += 1
        # Vertical runs
        for x in range(self.width):
            y = 0
            while y < self.height:
                cell = self.cells[y][x]
                if cell:
                    color = cell.color
                    run = [(x, y)]
                    y2 = y + 1
                    while y2 < self.height and self.cells[y2][x] and self.cells[y2][x].color == color:
                        run.append((x, y2))
                        y2 += 1
                    if len(run) >= 3:
                        to_clear.update(run)
                    y = y2
                else:
                    y += 1
        return to_clear

    def apply_gravity(self):
        for x in range(self.width):
            stack = [self.cells[y][x] for y in range(self.height) if self.cells[y][x] is not None]
            for y in range(self.height - 1, -1, -1):
                self.cells[y][x] = stack.pop() if stack else None

    def clear_positions(self, positions):
        for x, y in positions:
            self.cells[y][x] = None
        self.apply_gravity()
        return len(positions)

    def process_clears(self):
        total_score = 0
        chain = 0
        while True:
            cleared = False
            # Tetris line clears
            num_lines = self.clear_completed_lines()
            if num_lines > 0:
                chain += 1
                cleared = True
                score_per = LINE_CLEAR_SCORES.get(num_lines, num_lines * 200)
                total_score += score_per * chain
            # Bejeweled match-3 clears
            matches = self.find_match3()
            if matches:
                chain += 1
                cleared = True
                num_gems = self.clear_positions(matches)
                total_score += GEM_CLEAR_SCORE * num_gems * chain
            if not cleared:
                break
        return total_score

